plugin.detectCode:
const hasMdH = /^#{1,6}\s/m.test(input);
const hasHtmlH = /<h[1-6][^>]*>/i.test(input);
return (hasMdH || hasHtmlH) ? 0.95 : 0;

plugin.executeCode:
const lines = input.split('\n');
const outline = [];
for (const line of lines) {
  // Markdown headings
  const mdMatch = line.match(/^(#{1,6})\s+(.+)/);
  if (mdMatch) {
    const level = mdMatch[1].length;
    const text = mdMatch[2].replace(/#{1,6}\s*$/, '').trim(); // strip trailing hashes
    outline.push({ level, text });
    continue;
  }
  // HTML headings
  const htmlMatch = line.match(/<h([1-6])[^>]*>([^<]*)<\/h\1>/i);
  if (htmlMatch) {
    const level = parseInt(htmlMatch[1], 10);
    const text = htmlMatch[2].trim();
    outline.push({ level, text });
  }
}
if (outline.length === 0) {
  return { output: 'No headings found.', outputLanguage: 'text' };
}
const minLevel = Math.min(...outline.map(h => h.level));
const result = outline.map(h => {
  const indent = '  '.repeat(h.level - minLevel);
  return `${indent}${'H' + h.level}  ${h.text}`;
}).join('\n');
return { output: result, outputLanguage: 'text' };
